query:
UPDATE articles 
SET title = REPLACE(
  REPLACE(
    REPLACE(
      REPLACE(
        REPLACE(title, 'Best Best Best Best Best ', 'Best '),
        'Best Best Best Best ', 'Best '
      ),
      'Best Best Best ', 'Best '
    ),
    'Best Best ', 'Best '
  ),
  ' - -', ''
)
WHERE title LIKE '%Best Best%' OR title LIKE '% - -%';

